def human_review(state: CodeState) -> CodeState:
    if state["cycle_count"] > 3 or state.get("security_issues"):
        print(f"HUMAN REVIEW NEEDED: Cycle {state['cycle_count']}")
        print(f"Generated code: {state['generated_code'][:200]}...")
        approval = input("Approve? (y/n): ").lower() == 'y'
        return {"human_approved": approval}
    return {"human_approved": True}

