import vex

vex_client = vex.Client(api_key="your-vex-api-key")

def vex_security_node(state: CodeState) -> CodeState:
    verification = vex_client.verify(
        state["generated_code"],
        {
            "risk_profile": "medium",
            "verifications": ["security_vulnerability_scanning", "no_credential_leakage", "dependency_safety"]
        },
        context={"codebase_language": "python", "sandboxed": True}
    )

    state["vex_security_report"] = {
        "passed": verification.passed,
        "issues": verification.issues,
        "score": verification.score
    }

    return state

# Replace security scanner
graph.add_node("vex_security", vex_security_node)
graph.add_edge("sandbox", "vex_security")

def vex_state_validator(state: CodeState) -> CodeState:
    # Schema validation
    schema_check = vex_client.verify_schema(
        state,
        expected_schema={
            "type": "CodeState",
            "properties": {
                "generated_code": {"type": "string", "maxLength": 10000},
                "test_results": {"type": "object"},
                "cycle_count": {"type": "integer", "maximum": 10}
            }
        }
    )

    if not schema_check.passed:
        raise ValueError(f"State schema invalid: {schema_check.errors}")

    # Content validation
    code_check = vex_client.verify(
        state["generated_code"],
        {"verifications": ["code_correctness", "license_compliance"]}
    )

    state["state_validated"] = code_check.passed
    return state

# Add before checkpoint edges
graph.add_node("validate_state", vex_state_validator)
graph.add_edge("vex_security", "validate_state")
graph.add_conditional_edges(
    "validate_state",
    lambda s: END if s["state_validated"] else "generate"
)
